+/**
+ * SMS notification adapter — delivers notifications via SMS.
+ *
+ * Implements NotificationAdapter so it can be registered with
+ * NotificationService for the 'sms' channel.
+ *
+ * Features:
+ * - Message formatting per notification type (concise for SMS)
+ * - Recipient validation (basic phone number format)
+ * - Pluggable SMS transport for testing; swap for real provider in production
+ * - In-memory transport for testing
+ *
+ * NOTE: User preferences currently only support email channel opt-in/out.
+ * SMS preferences (enabled, per-category toggles, quiet hours, etc.) need
+ * to be added to UserPreferences before SMS can respect user preferences.
+ * See SMS_PREFERENCES_TODO.md for details.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationPayload,
+  NotificationResult,
+  NotificationType,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface SmsMessage {
+  to: string;
+  body: string;
+  sentAt: Date;
+}
+
+export interface SmsTransport {
+  sendSms(message: SmsMessage): Promise<{ success: boolean; error?: string }>;
+}
+
+export interface SmsAdapterConfig {
+  transport?: SmsTransport;
+}
+
+/**
+ * In-memory transport that stores SMS messages for inspection.
+ * Used when no external transport is provided.
+ */
+export class InMemorySmsTransport implements SmsTransport {
+  private messages: SmsMessage[] = [];
+
+  async sendSms(message: SmsMessage): Promise<{ success: boolean; error?: string }> {
+    this.messages.push(message);
+    return { success: true };
+  }
+
+  getMessages(): SmsMessage[] {
+    return [...this.messages];
+  }
+
+  clear(): void {
+    this.messages = [];
+  }
+}
+
+/**
+ * Basic phone number validation — requires digits, optional leading +,
+ * at least 10 digits total.
+ */
+const PHONE_REGEX = /^\+?\d{10,15}$/;
+
+function resolveRecipient(recipient: string): { valid: boolean; phone: string; error?: string } {
+  const trimmed = recipient.replace(/[\s\-().]/g, '');
+  if (!trimmed) {
+    return { valid: false, phone: '', error: 'Recipient is empty' };
+  }
+  if (!PHONE_REGEX.test(trimmed)) {
+    return { valid: false, phone: trimmed, error: `Invalid phone number: ${recipient.trim()}` };
+  }
+  return { valid: true, phone: trimmed };
+}
+
+function formatSmsBody(payload: NotificationPayload): string {
+  const formatters: Record<NotificationType, (p: NotificationPayload) => string> = {
+    'order:confirmation': (p) => {
+      const orderId = (p.metadata?.orderId as string) ?? 'N/A';
+      return `Order ${orderId} confirmed. ${p.body}`;
+    },
+    'order:status-update': (p) => {
+      const orderId = (p.metadata?.orderId as string) ?? 'N/A';
+      const newStatus = (p.metadata?.newStatus as string) ?? 'unknown';
+      return `Order ${orderId} is now ${newStatus}. ${p.body}`;
+    },
+    'user:welcome': (p) => `Welcome to TaskFlow Pro! ${p.body}`,
+    'user:profile-updated': (p) => `Profile updated. ${p.body}`,
+  };
+
+  const formatter = formatters[payload.type];
+  const text = formatter(payload);
+
+  // SMS messages are typically limited to 160 characters for a single segment
+  if (text.length > 160) {
+    return text.slice(0, 157) + '...';
+  }
+  return text;
+}
+
+export class SmsAdapter implements NotificationAdapter {
+  readonly channel = 'sms' as const;
+  private logger = new Logger('SmsAdapter');
+  private transport: SmsTransport;
+  private sentMessages: Array<{ to: string; body: string; sentAt: Date }> = [];
+
+  constructor(config?: SmsAdapterConfig) {
+    this.transport = config?.transport ?? new InMemorySmsTransport();
+  }
+
+  /**
+   * Send a notification as an SMS.
+   *
+   * Steps:
+   * 1. Resolve and validate the recipient phone number
+   * 2. Format the notification body (concise for SMS)
+   * 3. Send via the configured transport
+   *
+   * Must not throw — returns a failed NotificationResult on error.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    try {
+      // 1. Resolve recipient
+      const recipient = resolveRecipient(payload.recipient);
+      if (!recipient.valid) {
+        this.logger.warn(`Invalid recipient: ${recipient.error}`);
+        return { success: false, channel: 'sms', error: recipient.error };
+      }
+
+      // 2. Format message body
+      const body = formatSmsBody(payload);
+
+      // 3. Build and send SMS message
+      const message: SmsMessage = {
+        to: recipient.phone,
+        body,
+        sentAt: new Date(),
+      };
+
+      this.logger.info(`Sending SMS to ${recipient.phone}: ${payload.subject}`);
+
+      const result = await this.transport.sendSms(message);
+
+      // Track for getSentMessages()
+      if (result.success) {
+        this.sentMessages.push({
+          to: recipient.phone,
+          body,
+          sentAt: message.sentAt,
+        });
+      }
+
+      if (!result.success) {
+        this.logger.error(`Failed to send SMS to ${recipient.phone}: ${result.error}`);
+        return { success: false, channel: 'sms', error: result.error };
+      }
+
+      return { success: true, channel: 'sms' };
+    } catch (err) {
+      const errorMessage = err instanceof Error ? err.message : 'Unknown error';
+      this.logger.error(`Unexpected error sending SMS: ${errorMessage}`);
+      return { success: false, channel: 'sms', error: errorMessage };
+    }
+  }
+
+  /**
+   * Get all SMS messages sent by this adapter (useful for testing).
+   */
+  getSentMessages(): Array<{ to: string; body: string; sentAt: Date }> {
+    return [...this.sentMessages];
+  }
+
+  /**
+   * Clear sent message history (useful for testing).
+   */
+  clearSentMessages(): void {
+    this.sentMessages = [];
+  }
+
+  /**
+   * Get the underlying transport (useful for testing with InMemorySmsTransport).
+   */
+  getTransport(): SmsTransport {
+    return this.transport;
+  }
+}

