+import { describe, it, expect, beforeEach } from 'vitest';
+import {
+  SmsAdapter,
+  InMemorySmsTransport,
+} from '../../src/adapters/sms.adapter.js';
+import type {
+  SmsTransport,
+  SmsMessage,
+} from '../../src/adapters/sms.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+describe('SmsAdapter', () => {
+  let adapter: SmsAdapter;
+  let transport: InMemorySmsTransport;
+
+  beforeEach(() => {
+    transport = new InMemorySmsTransport();
+    adapter = new SmsAdapter({ transport });
+  });
+
+  describe('send', () => {
+    it('should send an order confirmation SMS with formatted body', async () => {
+      const payload: NotificationPayload = {
+        type: 'order:confirmation',
+        recipient: '+15551234567',
+        subject: 'Order Confirmation: order-1',
+        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+        metadata: { orderId: 'order-1', userId: 'user-1' },
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('sms');
+
+      const messages = transport.getMessages();
+      expect(messages).toHaveLength(1);
+      expect(messages[0]?.to).toBe('+15551234567');
+      expect(messages[0]?.body).toContain('Order order-1 confirmed');
+    });
+
+    it('should send an order status update SMS', async () => {
+      const payload: NotificationPayload = {
+        type: 'order:status-update',
+        recipient: '+15551234567',
+        subject: 'Order Update: order-1',
+        body: 'Your order status has changed from pending to confirmed.',
+        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      const messages = transport.getMessages();
+      expect(messages[0]?.body).toContain('Order order-1 is now confirmed');
+    });
+
+    it('should send a welcome SMS', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '+15559876543',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      const messages = transport.getMessages();
+      expect(messages[0]?.body).toContain('Welcome to TaskFlow Pro!');
+    });
+
+    it('should send a profile updated SMS', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:profile-updated',
+        recipient: '+15551234567',
+        subject: 'Profile Updated',
+        body: 'Your profile has been updated.',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      const messages = transport.getMessages();
+      expect(messages[0]?.body).toContain('Profile updated');
+    });
+
+    it('should truncate messages longer than 160 characters', async () => {
+      const payload: NotificationPayload = {
+        type: 'order:confirmation',
+        recipient: '+15551234567',
+        subject: 'Order Confirmation',
+        body: 'A'.repeat(200),
+        metadata: { orderId: 'order-1' },
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      const messages = transport.getMessages();
+      expect(messages[0]?.body.length).toBeLessThanOrEqual(160);
+      expect(messages[0]?.body).toMatch(/\.\.\.$/);
+    });
+
+    it('should track sent messages via getSentMessages()', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '+15551234567',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      await adapter.send(payload);
+
+      const sent = adapter.getSentMessages();
+      expect(sent).toHaveLength(1);
+      expect(sent[0]?.to).toBe('+15551234567');
+      expect(sent[0]?.body).toContain('Welcome');
+    });
+  });
+
+  describe('recipient validation', () => {
+    it('should reject empty recipient', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('empty');
+      expect(transport.getMessages()).toHaveLength(0);
+    });
+
+    it('should reject invalid phone number', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: 'not-a-phone',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid phone number');
+      expect(transport.getMessages()).toHaveLength(0);
+    });
+
+    it('should reject phone number that is too short', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '12345',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid phone number');
+    });
+
+    it('should strip formatting characters from phone number', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '+1 (555) 123-4567',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(transport.getMessages()[0]?.to).toBe('+15551234567');
+    });
+  });
+
+  describe('transport error handling', () => {
+    it('should return failed result when transport fails', async () => {
+      const failingTransport: SmsTransport = {
+        async sendSms(): Promise<{ success: boolean; error?: string }> {
+          return { success: false, error: 'SMS gateway unavailable' };
+        },
+      };
+
+      const failAdapter = new SmsAdapter({ transport: failingTransport });
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '+15551234567',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      const result = await failAdapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('SMS gateway unavailable');
+      expect(failAdapter.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should catch transport exceptions and return failed result', async () => {
+      const throwingTransport: SmsTransport = {
+        async sendSms(): Promise<{ success: boolean; error?: string }> {
+          throw new Error('Network timeout');
+        },
+      };
+
+      const throwAdapter = new SmsAdapter({ transport: throwingTransport });
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '+15551234567',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow Pro.',
+      };
+
+      const result = await throwAdapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Network timeout');
+    });
+  });
+
+  describe('configuration', () => {
+    it('should use InMemorySmsTransport by default', () => {
+      const defaultAdapter = new SmsAdapter();
+      expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemorySmsTransport);
+    });
+  });
+
+  describe('clearSentMessages', () => {
+    it('should clear sent message history', async () => {
+      const payload: NotificationPayload = {
+        type: 'user:welcome',
+        recipient: '+15551234567',
+        subject: 'Welcome!',
+        body: 'Welcome.',
+      };
+
+      await adapter.send(payload);
+      expect(adapter.getSentMessages()).toHaveLength(1);
+
+      adapter.clearSentMessages();
+      expect(adapter.getSentMessages()).toHaveLength(0);
+    });
+  });
+
+  describe('InMemorySmsTransport', () => {
+    it('should store and return messages', async () => {
+      const msg: SmsMessage = {
+        to: '+15551234567',
+        body: 'Test message',
+        sentAt: new Date(),
+      };
+
+      const result = await transport.sendSms(msg);
+
+      expect(result.success).toBe(true);
+      expect(transport.getMessages()).toHaveLength(1);
+      expect(transport.getMessages()[0]?.to).toBe('+15551234567');
+    });
+
+    it('should clear messages', async () => {
+      const msg: SmsMessage = {
+        to: '+15551234567',
+        body: 'Test message',
+        sentAt: new Date(),
+      };
+
+      await transport.sendSms(msg);
+      transport.clear();
+      expect(transport.getMessages()).toHaveLength(0);
+    });
+  });
+});

