/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements NotificationAdapter so it can be registered with
 * NotificationService for the 'sms' channel.
 *
 * Features:
 * - Message formatting per notification type (concise for SMS)
 * - Recipient validation (basic phone number format)
 * - Pluggable SMS transport for testing; swap for real provider in production
 * - In-memory transport for testing
 *
 * NOTE: User preferences currently only support email channel opt-in/out.
 * SMS preferences (enabled, per-category toggles, quiet hours, etc.) need
 * to be added to UserPreferences before SMS can respect user preferences.
 * See SMS_PREFERENCES_TODO.md for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
}

export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ success: boolean; error?: string }>;
}

export interface SmsAdapterConfig {
  transport?: SmsTransport;
}

/**
 * In-memory transport that stores SMS messages for inspection.
 * Used when no external transport is provided.
 */
export class InMemorySmsTransport implements SmsTransport {
  private messages: SmsMessage[] = [];

  async sendSms(message: SmsMessage): Promise<{ success: boolean; error?: string }> {
    this.messages.push(message);
    return { success: true };
  }

  getMessages(): SmsMessage[] {
    return [...this.messages];
  }

  clear(): void {
    this.messages = [];
  }
}

/**
 * Basic phone number validation — requires digits, optional leading +,
 * at least 10 digits total.
 */
const PHONE_REGEX = /^\+?\d{10,15}$/;

function resolveRecipient(recipient: string): { valid: boolean; phone: string; error?: string } {
  const trimmed = recipient.replace(/[\s\-().]/g, '');
  if (!trimmed) {
    return { valid: false, phone: '', error: 'Recipient is empty' };
  }
  if (!PHONE_REGEX.test(trimmed)) {
    return { valid: false, phone: trimmed, error: `Invalid phone number: ${recipient.trim()}` };
  }
  return { valid: true, phone: trimmed };
}

function formatSmsBody(payload: NotificationPayload): string {
  const formatters: Record<NotificationType, (p: NotificationPayload) => string> = {
    'order:confirmation': (p) => {
      const orderId = (p.metadata?.orderId as string) ?? 'N/A';
      return `Order ${orderId} confirmed. ${p.body}`;
    },
    'order:status-update': (p) => {
      const orderId = (p.metadata?.orderId as string) ?? 'N/A';
      const newStatus = (p.metadata?.newStatus as string) ?? 'unknown';
      return `Order ${orderId} is now ${newStatus}. ${p.body}`;
    },
    'user:welcome': (p) => `Welcome to TaskFlow Pro! ${p.body}`,
    'user:profile-updated': (p) => `Profile updated. ${p.body}`,
  };

  const formatter = formatters[payload.type];
  const text = formatter(payload);

  // SMS messages are typically limited to 160 characters for a single segment
  if (text.length > 160) {
    return text.slice(0, 157) + '...';
  }
  return text;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private sentMessages: Array<{ to: string; body: string; sentAt: Date }> = [];

  constructor(config?: SmsAdapterConfig) {
    this.transport = config?.transport ?? new InMemorySmsTransport();
  }

  /**
   * Send a notification as an SMS.
   *
   * Steps:
   * 1. Resolve and validate the recipient phone number
   * 2. Format the notification body (concise for SMS)
   * 3. Send via the configured transport
   *
   * Must not throw — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Resolve recipient
      const recipient = resolveRecipient(payload.recipient);
      if (!recipient.valid) {
        this.logger.warn(`Invalid recipient: ${recipient.error}`);
        return { success: false, channel: 'sms', error: recipient.error };
      }

      // 2. Format message body
      const body = formatSmsBody(payload);

      // 3. Build and send SMS message
      const message: SmsMessage = {
        to: recipient.phone,
        body,
        sentAt: new Date(),
      };

      this.logger.info(`Sending SMS to ${recipient.phone}: ${payload.subject}`);

      const result = await this.transport.sendSms(message);

      // Track for getSentMessages()
      if (result.success) {
        this.sentMessages.push({
          to: recipient.phone,
          body,
          sentAt: message.sentAt,
        });
      }

      if (!result.success) {
        this.logger.error(`Failed to send SMS to ${recipient.phone}: ${result.error}`);
        return { success: false, channel: 'sms', error: result.error };
      }

      return { success: true, channel: 'sms' };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Unexpected error sending SMS: ${errorMessage}`);
      return { success: false, channel: 'sms', error: errorMessage };
    }
  }

  /**
   * Get all SMS messages sent by this adapter (useful for testing).
   */
  getSentMessages(): Array<{ to: string; body: string; sentAt: Date }> {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history (useful for testing).
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }

  /**
   * Get the underlying transport (useful for testing with InMemorySmsTransport).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }
}

# SMS Channel: User Preferences Update Required

## Context

The SMS notification channel has been added (`src/adapters/sms.adapter.ts`), and `'sms'`
is now a valid `NotificationChannel`. However, **user preferences were designed assuming
email was the only notification channel**. The preferences model and service need to be
updated to support per-channel preference management.

## What changed

- `NotificationChannel` type now includes `'sms'` (in `src/models/notification.ts`)
- `SmsAdapter` implements `NotificationAdapter` and can be registered with `NotificationService`
- The "email-only" assumption that was baked into the preferences design is **no longer valid**

## What needs to change

### 1. `src/models/user-preferences.ts`

The `UserPreferences` interface currently has a single `email` field of type
`EmailNotificationPreferences`. This needs to support SMS (and potentially future channels):

```ts
// Current (email-only):
interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

// Needed (multi-channel):
interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  sms: SmsNotificationPreferences;    // NEW
  createdAt: Date;
  updatedAt: Date;
}
```

A new `SmsNotificationPreferences` interface is needed, similar to `EmailNotificationPreferences`
but with SMS-specific settings (e.g., no `frequency` digest option since SMS is always immediate,
but potentially `quietHours` for time-of-day restrictions).

### 2. `src/services/preferences.service.ts`

- Add a `shouldSendSms(userId, notificationType)` method (mirrors `shouldSendEmail`)
- Add `updateSmsPreferences(userId, input)` method
- Add default SMS preferences (likely all enabled, immediate)

### 3. `src/services/notification.service.ts`

The `deliverToChannels` method (line ~157) currently only checks preferences for the
`'email'` channel:

```ts
if (this.preferencesService && channel === 'email') {
  // ...
}
```

This needs to also check SMS preferences when `channel === 'sms'`:

```ts
if (this.preferencesService && channel === 'sms') {
  const userId = payload.metadata?.userId as string | undefined;
  if (userId && !this.preferencesService.shouldSendSms(userId, payload.type)) {
    // skip
  }
}
```

Consider refactoring to a generic `shouldSend(channel, userId, type)` method to
avoid adding a new `if` branch for every future channel.

### 4. `src/models/user-preferences.ts` — Defaults and mappings

- Add `DEFAULT_SMS_PREFERENCES` constant
- The existing `NOTIFICATION_TYPE_TO_CATEGORY` mapping is reusable across channels
  (the category names are the same), but verify this assumption holds

### 5. `src/repositories/preferences.repository.ts`

- Ensure storage/retrieval handles the new `sms` field
- Migration strategy for existing users who don't have SMS preferences yet
  (default to enabled or disabled?)

## Design decisions to make

1. **Default SMS opt-in**: Should new users have SMS enabled by default, or should it
   be opt-in only? (Email defaults to enabled — SMS may warrant a different default
   given cost and intrusiveness.)

2. **Phone number storage**: The SMS adapter validates phone numbers at send time, but
   user phone numbers need to be stored somewhere. The `User` model may need a `phone`
   field, or phone numbers could be part of preferences.

3. **Quiet hours**: SMS is more intrusive than email. Consider adding quiet-hours
   support to `SmsNotificationPreferences` to avoid sending at antisocial hours.

4. **Frequency**: SMS doesn't support digest mode — it should always be immediate.
   The preferences type should reflect this constraint.

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  SmsMessage,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ transport });
  });

  describe('send', () => {
    it('should send an order confirmation SMS with formatted body', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
        metadata: { orderId: 'order-1', userId: 'user-1' },
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');

      const messages = transport.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15551234567');
      expect(messages[0]?.body).toContain('Order order-1 confirmed');
    });

    it('should send an order status update SMS', async () => {
      const payload: NotificationPayload = {
        type: 'order:status-update',
        recipient: '+15551234567',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const messages = transport.getMessages();
      expect(messages[0]?.body).toContain('Order order-1 is now confirmed');
    });

    it('should send a welcome SMS', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '+15559876543',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const messages = transport.getMessages();
      expect(messages[0]?.body).toContain('Welcome to TaskFlow Pro!');
    });

    it('should send a profile updated SMS', async () => {
      const payload: NotificationPayload = {
        type: 'user:profile-updated',
        recipient: '+15551234567',
        subject: 'Profile Updated',
        body: 'Your profile has been updated.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const messages = transport.getMessages();
      expect(messages[0]?.body).toContain('Profile updated');
    });

    it('should truncate messages longer than 160 characters', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: '+15551234567',
        subject: 'Order Confirmation',
        body: 'A'.repeat(200),
        metadata: { orderId: 'order-1' },
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const messages = transport.getMessages();
      expect(messages[0]?.body.length).toBeLessThanOrEqual(160);
      expect(messages[0]?.body).toMatch(/\.\.\.$/);
    });

    it('should track sent messages via getSentMessages()', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '+15551234567',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      await adapter.send(payload);

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.body).toContain('Welcome');
    });
  });

  describe('recipient validation', () => {
    it('should reject empty recipient', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
      expect(transport.getMessages()).toHaveLength(0);
    });

    it('should reject invalid phone number', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'not-a-phone',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(transport.getMessages()).toHaveLength(0);
    });

    it('should reject phone number that is too short', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '12345',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should strip formatting characters from phone number', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '+1 (555) 123-4567',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(transport.getMessages()[0]?.to).toBe('+15551234567');
    });
  });

  describe('transport error handling', () => {
    it('should return failed result when transport fails', async () => {
      const failingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'SMS gateway unavailable' };
        },
      };

      const failAdapter = new SmsAdapter({ transport: failingTransport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '+15551234567',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
      expect(failAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should catch transport exceptions and return failed result', async () => {
      const throwingTransport: SmsTransport = {
        async sendSms(): Promise<{ success: boolean; error?: string }> {
          throw new Error('Network timeout');
        },
      };

      const throwAdapter = new SmsAdapter({ transport: throwingTransport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '+15551234567',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await throwAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Network timeout');
    });
  });

  describe('configuration', () => {
    it('should use InMemorySmsTransport by default', () => {
      const defaultAdapter = new SmsAdapter();
      expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemorySmsTransport);
    });
  });

  describe('clearSentMessages', () => {
    it('should clear sent message history', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: '+15551234567',
        subject: 'Welcome!',
        body: 'Welcome.',
      };

      await adapter.send(payload);
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('InMemorySmsTransport', () => {
    it('should store and return messages', async () => {
      const msg: SmsMessage = {
        to: '+15551234567',
        body: 'Test message',
        sentAt: new Date(),
      };

      const result = await transport.sendSms(msg);

      expect(result.success).toBe(true);
      expect(transport.getMessages()).toHaveLength(1);
      expect(transport.getMessages()[0]?.to).toBe('+15551234567');
    });

    it('should clear messages', async () => {
      const msg: SmsMessage = {
        to: '+15551234567',
        body: 'Test message',
        sentAt: new Date(),
      };

      await transport.sendSms(msg);
      transport.clear();
      expect(transport.getMessages()).toHaveLength(0);
    });
  });
});
